parameters.content:
=
<!DOCTYPE html>
<html>
<head>
<style>
  body { font-family: 'Helvetica', sans-serif; padding: 40px; }
  .header { text-align: center; border-bottom: 2px solid #0d9488; padding-bottom: 20px; margin-bottom: 30px; }
  .clinic-name { color: #0d9488; font-size: 24px; font-weight: bold; }
  .doctor-name { font-size: 18px; margin-top: 10px; }
  .patient-info { margin-bottom: 40px; }
  .content { min-height: 400px; font-size: 16px; line-height: 1.6; }
  .footer { text-align: center; margin-top: 50px; font-size: 12px; color: #666; }
  .signature { margin-top: 80px; text-align: center; }
  .signature-line { border-top: 1px solid #000; width: 200px; margin: 0 auto; padding-top: 5px; }
</style>
</head>
<body>
  <div class="header">
    <div class="clinic-name">MedFlow</div>
    <div class="doctor-name">Dr(a). {{ $('Webhook Supabase / Frontend').item.json.body.doctor_name }}</div>
    <div class="crm">CRM: {{ $('Webhook Supabase / Frontend').item.json.body.doctor_crm }}</div>
  </div>

  <div class="patient-info">
    <strong>Paciente:</strong> {{ $('Webhook Supabase / Frontend').item.json.body.patient_name }}<br>
    <strong>Data:</strong> {{ $now.setZone('America/Sao_Paulo').format('dd/MM/yyyy') }}
  </div>

  <h2 style="text-align: center; margin-bottom: 30px;">{{ $('Webhook Supabase / Frontend').item.json.body.document_type === 'receita' ? 'RECEITUÁRIO' : 'PEDIDO DE EXAMES' }}</h2>

  <div class="content">
    {{ $('Webhook Supabase / Frontend').item.json.body.content.replace(/\n/g, '<br>') }}
  </div>

  <div class="signature">
    <div class="signature-line">Assinatura e Carimbo</div>
  </div>
</body>
</html>

